-- Storage Gallery & Molecule Models
CREATE TABLE IF NOT EXISTS public.gallery_items (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  url TEXT NOT NULL,
  type TEXT NOT NULL,
  mime_type TEXT,
  filename TEXT,
