-- Audio Voice Logs
CREATE TABLE IF NOT EXISTS public.conversations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  owner uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  audio_url text
);
INSERT INTO storage.buckets (id, name, public) VALUES ('voice_conversations', 'voice_conversations', true) ON CONFLICT DO NOTHING;
DROP POLICY IF EXISTS "Public voice accessibility" ON storage.objects;
CREATE POLICY "Public voice accessibility" ON storage.objects FOR SELECT USING (bucket_id = 'voice_conversations');

-- Apply Central RLS Policies
ALTER TABLE public.notes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.finance_profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.finance_transactions ENABLE ROW LEVEL SECURITY;
