CREATE POLICY "Enable Read/Write For Table Owner" ON public.finance_profiles FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Enable Read/Write For Table Owner" ON public.finance_transactions FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Enable Read/Write For Table Owner" ON public.vehicles FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Enable Read/Write For Table Owner" ON public.gallery_items FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Enable Read/Write For Table Owner" ON public.user_molecules FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Enable Read/Write For Table Owner" ON public.dairy_items FOR ALL USING (auth.uid() = user_id);
