  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,
  status TEXT DEFAULT 'sent'
);
ALTER TABLE public.broadcasts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.broadcast_iterations ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public Read for Broadcasts" ON public.broadcasts FOR SELECT USING (true);
CREATE POLICY "User iteration records R/W" ON public.broadcast_iterations FOR ALL USING (auth.uid() = user_id);

