  if (req.method === 'OPTIONS') {
    return new Response('ok', {
      headers: corsHeaders
    });
  }

  // NEW: Check for multiple keys
  if (BROWSERLESS_API_KEYS.length === 0) {
    return new Response(JSON.stringify({
      error: "Server configuration error: BROWSERLESS_API_KEYS is not set."
    }), {
      headers: {
        ...corsHeaders,
        'Content-Type': 'application/json'
      },
      status: 200
    });
  }

  try {
    const { url } = await req.json();
    if (!url) {
      return new Response(JSON.stringify({
        error: "URL parameter is required."
      }), {
        headers: {
          ...corsHeaders,
          'Content-Type': 'application/json'
        },
        status: 200
      });
    }

    try {
      new URL(url);
    } catch (_) {
      return new Response(JSON.stringify({
        error: "Invalid URL format provided."
      }), {
        headers: {
          ...corsHeaders,
          'Content-Type': 'application/json'
        },
        status: 200
      });
    }

    let browserlessResponse;
    let lastError = null;

    // NEW: Loop through API keys on failure
    for (let i = 0; i < BROWSERLESS_API_KEYS.length; i++) {
      const apiKey = BROWSERLESS_API_KEYS[currentKeyIndex];
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30000); // Increased timeout to 30 seconds

      try {
        console.log(`Attempting to fetch with Browserless key ending in ...${apiKey.slice(-4)}`);
        const response = await fetch(`https://production-sfo.browserless.io/content?token=${apiKey}`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            url: url,
          }),
          signal: controller.signal
        });

        if (response.ok) {
          browserlessResponse = response;
          break; // Success, exit the loop
        }

        // Handle non-ok responses that might indicate a key issue
        const status = response.status;
        lastError = new Error(`Browserless API failed with status ${status}: ${await response.text()}`);

        if (status === 401 || status === 403 || status === 429) {
          console.warn(`Key ...${apiKey.slice(-4)} failed with status ${status}. Rotating.`);
          currentKeyIndex = (currentKeyIndex + 1) % BROWSERLESS_API_KEYS.length;
          continue; // Try the next key
        } else {
          // For other errors (like 500), no point in rotating keys, so throw immediately.
          throw lastError;
        }
      } catch (error) {
        lastError = error;
        if (error.name === 'AbortError') {
          // If it's a timeout, it might not be a key issue, but we'll try the next key just in case.
          console.warn(`Request timed out with key ...${apiKey.slice(-4)}. Rotating.`);
        } else {
          console.error(`Fetch error with key ...${apiKey.slice(-4)}:`, error.message);
        }
        // Rotate key and continue to the next iteration
        currentKeyIndex = (currentKeyIndex + 1) % BROWSERLESS_API_KEYS.length;
      } finally {
        clearTimeout(timeoutId);
      }
    }

    if (!browserlessResponse) {
      throw lastError || new Error("All Browserless API keys failed or the requests timed out.");
    }

    const html = await browserlessResponse.text();
    const doc = new DOMParser().parseFromString(html, 'text/html');

    if (!doc) {
      throw new Error("Failed to parse HTML document from Browserless response.");
    }

    const base = doc.createElement('base');
    base.setAttribute('href', url);
    doc.head.appendChild(base);

    const reader = new Readability(doc.cloneNode(true), {
      charThreshold: 250
    });

    const article = reader.parse();
    let title = article?.title;
    let textContent = '';

    if (article && article.textContent) {
      textContent = cleanText(article.textContent);
    } else {
      const mainContent = doc.querySelector('main')?.textContent || doc.querySelector('article')?.textContent || doc.body?.textContent;
      textContent = cleanText(mainContent);
      title = article?.title || doc.title || 'Untitled';
    }

    // REMOVED: The strict 100-character check to allow the AI to process pages with short content.
    return new Response(JSON.stringify({
      title,
      content: textContent
    }), {
      headers: {
        ...corsHeaders,
        'Content-Type': 'application/json'
      },
      status: 200
    });

  } catch (error) {
    let errorMessage = error.message;
    if (error.name === 'AbortError') {
      errorMessage = 'The request to the URL timed out after 30 seconds.'; // Updated error message
    }
    return new Response(JSON.stringify({
      error: errorMessage
    }), {
      headers: {
        ...corsHeaders,
        'Content-Type': 'application/json'
      },
      status: 200
    });
  }
});

